package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.Arrays;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withNonNullValues() throws Exception {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format);

        // Use reflection to override print and println behavior
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class);
        Method printlnMethod = CSVPrinter.class.getDeclaredMethod("println");

        // Create proxies by using a helper wrapper class
        CSVPrinter proxy = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        proxy.printRecord("a", 123, true);

        assertEquals("a123true\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withNullValues() throws Exception {
        StringBuilder appendable = new StringBuilder();

        CSVPrinter proxy = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        proxy.printRecord("a", null, "c");

        assertEquals("anullc\n", appendable.toString());
    }

    @Test
    void testPrintRecord_withEmptyValues() throws Exception {
        StringBuilder appendable = new StringBuilder();

        CSVPrinter proxy = new CSVPrinter(appendable, format) {
            @Override
            public void print(Object value) throws IOException {
                appendable.append(String.valueOf(value));
            }

            @Override
            public void println() throws IOException {
                appendable.append('\n');
            }
        };

        proxy.printRecord();

        assertEquals("\n", appendable.toString());
    }
}
